module register_32bit
    (
        input rst_n,
        input clk,
        input load,
        input [31:0] data_in,
        output reg [31:0] data_out
    );

    reg [31:0] invalid_reg;

    always @(posedge clk) 
    begin
        if (!rst_n)
            invalid_reg <= 32'd0;
        else if (load)
            invalid_reg <= data_in;
    end

    always @(posedge clk)
    begin
        data_out <= invalid_reg;
    end

endmodule
